        data: {"result": {"minY": 1.0, "minX": 0.0, "maxY": 2000.0, "series": [{"data": [[0.0, 2000.0]], "isOverall": false, "label": "POST /recommend/exposures", "isController": false}, {"data": [[0.0, 11.0], [100.0, 1983.0], [200.0, 6.0]], "isOverall": false, "label": "GET /recommend/discover small page", "isController": false}, {"data": [[300.0, 584.0], [600.0, 18.0], [700.0, 1.0], [400.0, 1295.0], [200.0, 1.0], [500.0, 101.0]], "isOverall": false, "label": "GET /recommend/discover default", "isController": false}, {"data": [[300.0, 231.0], [600.0, 17.0], [700.0, 3.0], [800.0, 1.0], [400.0, 1557.0], [200.0, 1.0], [500.0, 190.0]], "isOverall": false, "label": "GET /recommend/discover tag filter", "isController": false}, {"data": [[300.0, 542.0], [600.0, 14.0], [700.0, 2.0], [200.0, 40.0], [400.0, 1286.0], [500.0, 116.0]], "isOverall": false, "label": "GET /recommend/discover next page", "isController": false}], "supportsControllersDiscrimination": true, "granularity": 100, "maxX": 800.0, "title": "Response Time Distribution"}},
